const apiResponse = $json;
const passStateData = $('Pass State').item.json;

const prevCompanies = passStateData.allCompanies || [];
const newCompanies = apiResponse.results || [];
const cursor = apiResponse.paging?.next?.after || null;

return {
  json: {
    after: cursor,
    allCompanies: [...prevCompanies, ...newCompanies]
  }
};

const allCompanies = $input.first().json.allCompanies || [];
return allCompanies.map(company => ({
  json: {
    id: String(company.id),
    properties: company.properties || {}
  }
}));

const items = $input.all();
const companies = items.map((item, index) => ({
  index,
  name: item.json.companyName,
  domain: item.json.domain
}));

const prompt = 'You are an expert at identifying corporate subsidiaries, branches, and regional offices.\n\n'
  + 'For each company below, determine if it is:\n'
  + '- An INDEPENDENT company (standalone business)\n'
  + '- A SUBSIDIARY/BRANCH/REGIONAL OFFICE of a larger parent company\n\n'
  + 'Indicators of subsidiaries/branches:\n'
  + '- Country or city names in the company name (e.g., "KPMG Spain", "Deloitte UK", "Google Germany")\n'
  + '- Regional indicators (e.g., "EMEA", "Asia Pacific", "Latin America")\n'
  + '- "Branch", "Office", "Division", "Chapter" in the name\n'
  + '- Well-known subsidiary relationships (e.g., Instagram -> Meta, YouTube -> Alphabet)\n\n'
  + 'COMPANIES TO CLASSIFY:\n'
  + companies.map(c => '[' + c.index + '] "' + c.name + '" (domain: ' + (c.domain || 'none') + ')').join('\n')
  + '\n\nReturn ONLY a valid JSON array (no markdown, no explanation):\n'
  + '[{"index": 0, "isSubsidiary": false, "parentCompany": null, "parentDomain": null}]\n\n'
  + 'Rules:\n'
  + '- For independent companies: isSubsidiary=false, parentCompany=null, parentDomain=null\n'
  + '- For subsidiaries: isSubsidiary=true, parentCompany=parent name, parentDomain=parent primary domain (e.g., "kpmg.com" not "kpmg.es")\n'
  + '- When unsure, default to independent (isSubsidiary=false)';

const companyData = items.map(item => item.json);

return [{
  json: {
    prompt,
    companyData: JSON.stringify(companyData),
    companyCount: companies.length
  }
}];

const geminiResponse = $input.first().json;
const prepData = $('Prepare Gemini Batch').first().json;
const companyData = JSON.parse(prepData.companyData);

let classifications = [];
try {
  const text = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  classifications = JSON.parse(cleaned);
} catch (e) {
  classifications = companyData.map((_, i) => ({
    index: i,
    isSubsidiary: false,
    parentCompany: null,
    parentDomain: null
  }));
}

return companyData.map((company, index) => {
  const classification = classifications.find(c => c.index === index) || {
    isSubsidiary: false,
    parentCompany: null,
    parentDomain: null
  };

  const enrichmentDomain = classification.isSubsidiary && classification.parentDomain
    ? classification.parentDomain
    : company.domain;

  return {
    json: {
      companyId: company.companyId,
      companyName: company.companyName,
      domain: company.domain,
      linkedinUrl: company.linkedinUrl,
      existingEmployeeCount: company.existingEmployeeCount,
      isSubsidiary: classification.isSubsidiary || false,
      parentCompany: classification.parentCompany || null,
      parentDomain: classification.parentDomain || null,
      enrichmentDomain: enrichmentDomain
    }
  };
});

const items = $input.all();
const companies = [];
const allCompanyData = [];

for (const item of items) {
  const d = item.json;
  allCompanyData.push(d);

  const entry = {};
  if (d.enrichmentDomain) entry.domain = d.enrichmentDomain;
  if (d.linkedinUrl && !d.isSubsidiary) entry.linkedin_url = d.linkedinUrl;
  if (d.isSubsidiary && d.enrichmentDomain) {
    entry.domain = d.enrichmentDomain;
  }

  if (Object.keys(entry).length > 0) {
    companies.push(entry);
  }
}

return [{
  json: {
    batchPayload: { companies },
    allCompanyData: JSON.stringify(allCompanyData),
    totalCompanies: allCompanyData.length,
    batchSize: companies.length
  }
}];

const submitResponse = $json;
const batchData = $('Build Batch Request').first().json;

return {
  json: {
    requestId: submitResponse.id || submitResponse.request_id || submitResponse.data?.id || '',
    pollCount: 0,
    maxPolls: 20,
    allCompanyData: batchData.allCompanyData,
    totalCompanies: batchData.totalCompanies
  }
};

const apiResponse = $json;
const state = $('Wait 15s').item.json;

const isCompleted = apiResponse.status === 'completed' || apiResponse.data?.status === 'completed';
const pollCount = (state.pollCount || 0) + 1;
const maxReached = pollCount >= (state.maxPolls || 20);

return {
  json: {
    pollResponse: apiResponse,
    requestId: state.requestId,
    pollCount,
    maxPolls: state.maxPolls || 20,
    allCompanyData: state.allCompanyData,
    totalCompanies: state.totalCompanies,
    isComplete: isCompleted || maxReached
  }
};

return {
  json: {
    requestId: $json.requestId,
    pollCount: $json.pollCount,
    maxPolls: $json.maxPolls,
    allCompanyData: $json.allCompanyData,
    totalCompanies: $json.totalCompanies
  }
};

const input = $input.first().json;
const pollResponse = input.pollResponse || input;
const allCompanyData = JSON.parse(input.allCompanyData || '[]');
const results = pollResponse.results || pollResponse.data?.results || pollResponse.companies || [];

const resultsByDomain = {};
const resultsByLinkedin = {};
for (const r of results) {
  if (r.domain) resultsByDomain[r.domain.toLowerCase()] = r;
  if (r.linkedin_url) resultsByLinkedin[r.linkedin_url.toLowerCase()] = r;
}

return allCompanyData.map(company => {
  let match = null;
  if (company.enrichmentDomain) {
    match = resultsByDomain[company.enrichmentDomain.toLowerCase()];
  }
  if (!match && company.linkedinUrl && !company.isSubsidiary) {
    match = resultsByLinkedin[company.linkedinUrl.toLowerCase()];
  }

  const employeeCount = match
    ? (match.estimated_number_of_employees || match.employee_count || match.employees || match.headcount || match.number_of_employees || 0)
    : 0;

  return {
    json: {
      companyId: company.companyId,
      companyName: company.companyName,
      domain: company.domain,
      linkedinUrl: company.linkedinUrl,
      enrichmentDomain: company.enrichmentDomain,
      isSubsidiary: company.isSubsidiary,
      parentCompany: company.parentCompany,
      employeeCount: parseInt(employeeCount) || 0
    }
  };
});

const d = $json;
let enrichmentSource = 'Amplemarket';
if (d.isSubsidiary && d.parentCompany) {
  enrichmentSource = 'Amplemarket (parent: ' + d.parentCompany + ')';
}

return {
  json: {
    companyId: d.companyId,
    companyName: d.companyName,
    domain: d.domain,
    isSubsidiary: d.isSubsidiary,
    parentCompany: d.parentCompany,
    employeeCount: d.employeeCount,
    enrichmentSource
  }
};

const response = $json;
const prepData = $('Prep Estimate Prompt').item.json;

let employeeCount = 5;
try {
  const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const result = JSON.parse(cleaned);
  employeeCount = parseInt(result.employeeCount) || 5;
} catch (e) {
  employeeCount = 5;
}

return {
  json: {
    companyId: prepData.companyId,
    companyName: prepData.companyName,
    domain: prepData.domain,
    isSubsidiary: prepData.isSubsidiary,
    parentCompany: prepData.parentCompany,
    employeeCount,
    enrichmentSource: 'Estimated'
  }
};

let companyId, companyName, domain, isSubsidiary, parentCompany;

try {
  const cd = $('Check Has Domain').item.json;
  companyId = cd.companyId;
  companyName = cd.companyName;
  domain = cd.domain;
  isSubsidiary = cd.isSubsidiary;
  parentCompany = cd.parentCompany;
} catch(e) {
  companyId = $json.companyId;
  companyName = $json.companyName;
  domain = $json.domain;
  isSubsidiary = $json.isSubsidiary;
  parentCompany = $json.parentCompany;
}

return {
  json: {
    companyId: companyId || '',
    companyName: companyName || '',
    domain: domain || '',
    isSubsidiary: isSubsidiary || false,
    parentCompany: parentCompany || null,
    employeeCount: 5,
    enrichmentSource: 'Estimated'
  }
};

const r = $('Preserve Pre-Update').item.json;
return {
  json: {
    companyId: r.companyId,
    companyName: r.companyName,
    domain: r.domain,
    isSubsidiary: r.isSubsidiary,
    parentCompany: r.parentCompany,
    employeeCount: r.employeeCount,
    enrichmentSource: r.enrichmentSource
  }
};

const items = $json.data || [];

if (items.length === 0) {
  return { json: { message: 'No companies processed for employee enrichment today.' } };
}

const today = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
let amplemarket = 0;
let parentEnriched = 0;
let estimated = 0;
const details = [];

for (const d of items) {
  if (d.enrichmentSource === 'Estimated') {
    estimated++;
    details.push('\ud83d\udd0d ' + d.companyName + ' \u2192 ' + d.employeeCount + ' employees (Estimated)');
  } else if (d.enrichmentSource && d.enrichmentSource.startsWith('Amplemarket (parent:')) {
    parentEnriched++;
    details.push('\ud83c\udfe2 ' + d.companyName + ' \u2192 ' + d.employeeCount + ' employees (' + d.enrichmentSource + ')');
  } else {
    amplemarket++;
    details.push('\u2705 ' + d.companyName + ' \u2192 ' + d.employeeCount + ' employees (Amplemarket)');
  }
}

const total = items.length;
const message = '*Employee Count Enrichment v2.0 \u2014 ' + today + '*\n'
  + 'Total processed: ' + total + '\n'
  + '\u2705 Amplemarket: ' + amplemarket + '\n'
  + '\ud83c\udfe2 Parent enriched: ' + parentEnriched + '\n'
  + '\ud83d\udd0d Estimated: ' + estimated + '\n\n'
  + '*Details:*\n'
  + details.slice(0, 50).join('\n');

return { json: { message } };
